  ];

  static SENSITIVE_FIELDS = [
    'apiKey',
    'api_key',
    'token',
    'secret',
    'password',
    'private_key',
    'privateKey',
    'accessToken',
    'access_token',
    'refreshToken',
    'refresh_token',
  ];

  /**
   * Redact API keys and sensitive data from text
   */
  static redact(text, showPrefix = true) {
    if (!text) return text;

    let redacted = text;

    // Redact using patterns
