}

export class KeyRedactor {
  private static readonly API_KEY_PATTERNS = [
    // Anthropic API keys
    /sk-ant-[a-zA-Z0-9_-]{95,}/gi,

    // OpenRouter API keys
    /sk-or-[a-zA-Z0-9_-]{32,}/gi,

    // Google/Gemini API keys
